mapper.select:
SELECT d.id AS deliverable_id, d.outsource_task_id, ot.task_id AS project_task_id, d.deliverable_type, d.file_name, d.file_url, d.remark, d.create_time AS submit_time, p.id AS project_id, p.project_name, t.task_name, ac.id AS agent_company_id, ac.company_name AS agent_company_name, ot.status AS outsource_status, ot.deadline FROM outsource_deliverable d INNER JOIN outsource_task ot ON ot.id = d.outsource_task_id AND ot.deleted = 0 INNER JOIN project_task t ON t.id = ot.task_id AND t.deleted = 0 INNER JOIN project p ON p.id = ot.project_id AND p.deleted = 0 LEFT JOIN agent_company ac ON ac.id = ot.agent_company_id AND ac.deleted = 0 WHERE d.deleted = 0 AND p.pm_id = #{userId}
AND ot.status = #{status}
ORDER BY d.create_time DESC
LIMIT #{limit}

SELECT COUNT(*) FROM project
WHERE deleted = 0 AND pm_id = #{userId}
  AND status NOT IN ('CLOSE', 'ARCHIVED', 'CANCELLED')

SELECT
    COUNT(*) AS total,
    SUM(CASE WHEN status IN ('CLOSE','ARCHIVED') THEN 1 ELSE 0 END) AS completed,
    SUM(CASE WHEN status NOT IN ('CLOSE','ARCHIVED','CANCELLED') THEN 1 ELSE 0 END) AS ongoing,
    SUM(CASE WHEN planned_end IS NOT NULL AND planned_end < CURDATE()
              AND status NOT IN ('CLOSE','ARCHIVED','CANCELLED') THEN 1 ELSE 0 END) AS overdue,
    COALESCE(ROUND(AVG(progress_pct), 2), 0) AS avgProgress
FROM project
WHERE deleted = 0
  AND status = #{status}
  AND pm_id = #{pmId}
  AND product_line = #{productLine}
  AND region = #{region}

SELECT COALESCE(product_line, '未分类') AS productLine, COUNT(*) AS count
FROM project
WHERE deleted = 0
  AND status = #{status}
  AND pm_id = #{pmId}
  AND product_line = #{productLine}
  AND region = #{region}
GROUP BY product_line
ORDER BY count DESC

SELECT COALESCE(region, '未分类') AS region, COUNT(*) AS count
FROM project
WHERE deleted = 0
  AND status = #{status}
  AND pm_id = #{pmId}
  AND product_line = #{productLine}
  AND region = #{region}
GROUP BY region
ORDER BY count DESC
